#!/bin/sh
set -eu

SCRIPT_DIR=$(CDPATH= cd -- "$(dirname "$0")" && pwd)
GNOSIS_ROOT=$SCRIPT_DIR
PREFIX=${GNOSIS_INSTALL_PREFIX:-"$HOME/.gnosis"}
ARTIFACT_URL=${GNOSIS_ARTIFACT_URL:-}
ARTIFACT_DIR=${GNOSIS_ARTIFACT_DIR:-}
WITH_MOONSHINE=0
FROM_SOURCE=0
DRY_RUN=0
FORCE=0
UPDATE_PATH=1

log() {
  printf '%s\n' "$*"
}

die() {
  printf 'gnosis installer: %s\n' "$*" >&2
  exit 1
}

usage() {
  cat <<'EOF'
Usage: ./install.sh [options]

Installs user-facing Gnosis commands without the monorepo developer setup.

Options:
  --prefix <dir>          Install prefix (default: ~/.gnosis)
  --artifact-url <url>    Download and install a release bundle
  --artifact-dir <dir>    Install from an unpacked release bundle
  --from-source           Build native binaries from this checkout when possible
  --with-moonshine        Also install moonshine
  --no-path               Do not update shell startup files
  --dry-run               Print actions without writing
  --force                 Replace existing installed package tree
  -h, --help              Show this help

Release bundles may contain either:
  gnosis/                 package tree used by the command wrappers
  bin/monster             native monster binary
  bin/gnexec              native gnexec binary
  bin/moonshine           optional moonshine binary
  gnosis-install-manifest.json
EOF
}

while [ "$#" -gt 0 ]; do
  case "$1" in
    --prefix)
      [ "$#" -ge 2 ] || die "--prefix requires a value"
      PREFIX=$2
      shift 2
      ;;
    --artifact-url)
      [ "$#" -ge 2 ] || die "--artifact-url requires a value"
      ARTIFACT_URL=$2
      shift 2
      ;;
    --artifact-dir)
      [ "$#" -ge 2 ] || die "--artifact-dir requires a value"
      ARTIFACT_DIR=$2
      shift 2
      ;;
    --from-source)
      FROM_SOURCE=1
      shift
      ;;
    --with-moonshine)
      WITH_MOONSHINE=1
      shift
      ;;
    --no-path)
      UPDATE_PATH=0
      shift
      ;;
    --dry-run)
      DRY_RUN=1
      shift
      ;;
    --force)
      FORCE=1
      shift
      ;;
    -h|--help)
      usage
      exit 0
      ;;
    *)
      die "unknown option: $1"
      ;;
  esac
done

BIN_DIR="$PREFIX/bin"
LIB_DIR="$PREFIX/lib/gnosis"
COMMAND_ROOT="$LIB_DIR"

run() {
  if [ "$DRY_RUN" -eq 1 ]; then
    printf '[dry-run] %s\n' "$*"
  else
    "$@"
  fi
}

command_exists() {
  command -v "$1" >/dev/null 2>&1
}

host_target() {
  os=$(uname -s | tr '[:upper:]' '[:lower:]')
  arch=$(uname -m)
  case "$arch" in
    x86_64|amd64) arch=x64 ;;
    arm64|aarch64) arch=arm64 ;;
  esac
  case "$os" in
    darwin) os=macos ;;
    linux) os=linux ;;
    msys*|mingw*|cygwin*) os=windows ;;
  esac
  printf '%s-%s\n' "$os" "$arch"
}

download_artifact() {
  [ -n "$ARTIFACT_URL" ] || return 0
  tmp=${TMPDIR:-/tmp}/gnosis-install-$$
  run mkdir -p "$tmp"
  archive="$tmp/artifact"
  if command_exists curl; then
    run curl -fsSL "$ARTIFACT_URL" -o "$archive"
  elif command_exists wget; then
    run wget -q "$ARTIFACT_URL" -O "$archive"
  else
    die "curl or wget is required for --artifact-url"
  fi
  case "$ARTIFACT_URL" in
    *.zip)
      command_exists unzip || die "unzip is required for zip artifacts"
      run unzip -q "$archive" -d "$tmp/unpacked"
      ;;
    *.tar.gz|*.tgz)
      run mkdir -p "$tmp/unpacked"
      run tar -xzf "$archive" -C "$tmp/unpacked"
      ;;
    *)
      die "artifact URL must end in .tar.gz, .tgz, or .zip"
      ;;
  esac
  ARTIFACT_DIR="$tmp/unpacked"
}

copy_tree() {
  src=$1
  dst=$2
  [ -d "$src" ] || die "source tree not found: $src"
  if [ -e "$dst" ] && [ "$FORCE" -ne 1 ]; then
    die "$dst already exists; use --force to replace it"
  fi
  run rm -rf "$dst"
  run mkdir -p "$(dirname "$dst")"
  if command_exists rsync; then
    run rsync -a \
      --exclude node_modules \
      --exclude target \
      --exclude .git \
      --exclude .lake \
      --exclude distributed-inference/target-flux-txt2img \
      "$src"/ "$dst"/
  else
    run mkdir -p "$dst"
    run cp -R "$src"/. "$dst"/
  fi
}

install_from_artifact_dir() {
  [ -n "$ARTIFACT_DIR" ] || return 1
  [ -d "$ARTIFACT_DIR" ] || die "artifact directory not found: $ARTIFACT_DIR"
  target=$(host_target)
  if [ -d "$ARTIFACT_DIR/$target" ]; then
    ARTIFACT_DIR="$ARTIFACT_DIR/$target"
  fi
  [ -d "$ARTIFACT_DIR/gnosis" ] || die "artifact bundle must contain a gnosis/ package tree"
  copy_tree "$ARTIFACT_DIR/gnosis" "$LIB_DIR"
  run mkdir -p "$LIB_DIR/polyglot/target/release"
  if [ -f "$ARTIFACT_DIR/bin/monster" ]; then
    run cp "$ARTIFACT_DIR/bin/monster" "$LIB_DIR/polyglot/target/release/monster"
    run chmod +x "$LIB_DIR/polyglot/target/release/monster"
  fi
  if [ -f "$ARTIFACT_DIR/bin/gnexec" ]; then
    run cp "$ARTIFACT_DIR/bin/gnexec" "$LIB_DIR/polyglot/target/release/gnexec"
    run chmod +x "$LIB_DIR/polyglot/target/release/gnexec"
  fi
  if [ "$WITH_MOONSHINE" -eq 1 ] && [ -f "$ARTIFACT_DIR/bin/moonshine" ]; then
    run mkdir -p "$LIB_DIR/moonshine/target/release"
    run cp "$ARTIFACT_DIR/bin/moonshine" "$LIB_DIR/moonshine/target/release/moonshine"
    run chmod +x "$LIB_DIR/moonshine/target/release/moonshine"
  fi
  if [ "$DRY_RUN" -eq 1 ]; then
    return 0
  fi
  [ -d "$LIB_DIR" ]
}

install_from_checkout() {
  if [ ! -f "$GNOSIS_ROOT/bin/gnode.js" ]; then
    die "this script must run from an open-source/gnosis checkout or release bundle"
  fi
  COMMAND_ROOT="$GNOSIS_ROOT"
  run mkdir -p "$(dirname "$LIB_DIR")"
  log "Using checkout package tree: $GNOSIS_ROOT"
}

checkout_can_build_native() {
  [ -f "$GNOSIS_ROOT/polyglot/Cargo.toml" ] && [ -d "$GNOSIS_ROOT/../../gnot" ]
}

build_native_from_source() {
  [ "$FROM_SOURCE" -eq 1 ] || return 0
  command_exists cargo || die "--from-source requires cargo"
  checkout_can_build_native || die "isolated open-source/gnosis checkouts cannot build native monster/gnexec; use a release artifact"
  if [ "$DRY_RUN" -eq 1 ]; then
    log "[dry-run] cargo build --manifest-path $GNOSIS_ROOT/polyglot/Cargo.toml --bin monster --bin gnexec --release --target-dir $GNOSIS_ROOT/polyglot/target"
  else
    cargo build --manifest-path "$GNOSIS_ROOT/polyglot/Cargo.toml" --bin monster --bin gnexec --release --target-dir "$GNOSIS_ROOT/polyglot/target"
  fi
}

build_moonshine_from_source() {
  [ "$WITH_MOONSHINE" -eq 1 ] || return 0
  if [ -x "$LIB_DIR/moonshine/target/release/moonshine" ]; then
    return 0
  fi
  [ "$FROM_SOURCE" -eq 1 ] || die "--with-moonshine requires an artifact moonshine binary or --from-source"
  command_exists cargo || die "--with-moonshine --from-source requires cargo"
  if [ "$DRY_RUN" -eq 1 ]; then
    log "[dry-run] cargo build --release in $GNOSIS_ROOT/moonshine"
  else
    (cd "$GNOSIS_ROOT/moonshine" && cargo build --release)
    run mkdir -p "$LIB_DIR/moonshine/target/release"
    run cp "$GNOSIS_ROOT/moonshine/target/release/moonshine" "$LIB_DIR/moonshine/target/release/moonshine"
    run chmod +x "$LIB_DIR/moonshine/target/release/moonshine"
  fi
}

write_unix_wrapper() {
  name=$1
  path="$BIN_DIR/$name"
  run mkdir -p "$BIN_DIR"
  if [ "$DRY_RUN" -eq 1 ]; then
    log "[dry-run] write $path"
    return 0
  fi
  cat > "$path" <<EOF
#!/bin/sh
set -eu
GNOSIS_ROOT="$COMMAND_ROOT"
cmd=\$(basename "\$0")
node_bin=\${GNOSIS_NODE:-}
if [ -z "\$node_bin" ]; then
  node_bin=\$(command -v node 2>/dev/null || true)
fi
native_monster="\$GNOSIS_ROOT/polyglot/target/release/monster"
native_gnexec="\$GNOSIS_ROOT/polyglot/target/release/gnexec"
gnode_cli="\$GNOSIS_ROOT/bin/gnode.js"
gnosis_cli="\$GNOSIS_ROOT/bin/gnosis.js"
moonshine_bin="\$GNOSIS_ROOT/moonshine/target/release/moonshine"
need_node() {
  if [ -z "\$node_bin" ]; then
    echo "\$cmd: node is required for this command path" >&2
    exit 127
  fi
}
case "\$cmd" in
  gnexec)
    if [ -x "\$native_gnexec" ]; then exec "\$native_gnexec" "\$@"; fi
    if [ -x "\$native_monster" ]; then exec "\$native_monster" "\$@"; fi
    echo "gnexec: native binary not installed; reinstall with an artifact or --from-source" >&2
    exit 127
    ;;
  monster)
    if [ "\${1:-}" = "native" ]; then
      shift
      if [ -x "\$native_monster" ]; then exec "\$native_monster" "\$@"; fi
      echo "monster: native binary not installed; reinstall with an artifact or --from-source" >&2
      exit 127
    fi
    need_node
    case "\${1:-}" in
      *.mjs|*.cjs) exec "\$node_bin" "\$@" ;;
      *.ts|*.tsx|*.js|*.sh|*.gg|*.gnot|*.py|*.go|*.rs|*.rb|*.java|*.c|*.cpp|*.cc|*.kt|*.zig|*.lua|*.ex|*.exs)
        export GNODE_TRUST_PREWARMED_BUNDLE=\${GNODE_TRUST_PREWARMED_BUNDLE:-1}
        exec "\$node_bin" "\$gnode_cli" run "\$@"
        ;;
      *)
        export GNODE_TRUST_PREWARMED_BUNDLE=\${GNODE_TRUST_PREWARMED_BUNDLE:-1}
        exec "\$node_bin" "\$gnode_cli" "\$@"
        ;;
    esac
    ;;
  gnode)
    need_node
    export GNODE_TRUST_PREWARMED_BUNDLE=\${GNODE_TRUST_PREWARMED_BUNDLE:-1}
    exec "\$node_bin" "\$gnode_cli" "\$@"
    ;;
  gnosis)
    need_node
    exec "\$node_bin" "\$gnosis_cli" "\$@"
    ;;
  gg)
    need_node
    case "\${1:-}" in
      --help|-h|help)
        cat <<'GG_HELP'
Usage:
  gg <file.gg|file.gnot> [args...]   run a GG source through gnode
  gg <gnosis-args...>                forward to the gnosis CLI

Examples:
  gg example.gg
  gg lint example.gg
GG_HELP
        exit 0
        ;;
      *.gg|*.gnot)
        export GNODE_TRUST_PREWARMED_BUNDLE=\${GNODE_TRUST_PREWARMED_BUNDLE:-1}
        exec "\$node_bin" "\$gnode_cli" run "\$@"
        ;;
      *)
        exec "\$node_bin" "\$gnosis_cli" "\$@"
        ;;
    esac
    ;;
  moonshine)
    if [ -x "\$moonshine_bin" ]; then exec "\$moonshine_bin" "\$@"; fi
    echo "moonshine: not installed; rerun install.sh --with-moonshine" >&2
    exit 127
    ;;
esac
EOF
  chmod +x "$path"
}

update_shell_path() {
  [ "$UPDATE_PATH" -eq 1 ] || return 0
  marker="# Gnosis user command path"
  line="export PATH=\"$BIN_DIR:\$PATH\""
  for rc in "$HOME/.zshrc" "$HOME/.bashrc" "$HOME/.profile"; do
    [ -f "$rc" ] || continue
    if grep -Fq "$BIN_DIR" "$rc"; then
      continue
    fi
    if [ "$DRY_RUN" -eq 1 ]; then
      log "[dry-run] add $BIN_DIR to $rc"
    else
      {
        printf '\n%s\n' "$marker"
        printf '%s\n' "$line"
      } >> "$rc"
    fi
    return 0
  done
  log "Add this to your shell startup file:"
  log "$line"
}

download_artifact
build_native_from_source
if ! install_from_artifact_dir; then
  install_from_checkout
fi
build_moonshine_from_source

for cmd in gnosis gnode monster gnexec gg; do
  write_unix_wrapper "$cmd"
done
if [ "$WITH_MOONSHINE" -eq 1 ]; then
  write_unix_wrapper moonshine
  if [ "$DRY_RUN" -ne 1 ] && [ -x "$BIN_DIR/moonshine" ] && [ ! -f "$HOME/.moonshine.knot" ]; then
    "$BIN_DIR/moonshine" init >/dev/null 2>&1 || true
  fi
fi
update_shell_path

log "Gnosis commands installed in $BIN_DIR"
log "Open a new terminal or run: export PATH=\"$BIN_DIR:\$PATH\""
